type LogoProps = MarkProps & {
  /** Show the "Hometowne / HONEY" wordmark beneath the mark. */
  wordmark?: boolean;
  /** Color of the wordmark text (defaults to a brand brown gold). */
  wordmarkColor?: string;
};

/** The full lock-up: vector mark, optionally over the Hometowne Honey wordmark. */
export function Logo({
  size = 76,
  wordmark = false,
  wordmarkColor = '#BC8A26',
}: LogoProps) {
  const width = size;
  const height = size * (120.31046 / 107.9416);

  return (
    <View style={{ alignItems: 'center' }}>
      <LogoMark size={size} />
      {wordmark && (
        <View style={{ alignItems: 'center', marginTop: 12 }}>
          <Text
            style={{
              fontFamily: 'PlayfairDisplay_900Black',
              color: wordmarkColor,
              letterSpacing: size * 0.04,
            }}
          >
            <Text style={{ fontSize: size * 0.42 }}>H</Text>
            <Text style={{ fontSize: size * 0.36 }}>OMETOWNE</Text>
          </Text>
          <Text
            style={{
              fontFamily: 'DMSans_700Bold',
              fontSize: size * 0.13,
              color: wordmarkColor,
              letterSpacing: size * 0.06,
              textTransform: 'uppercase',
              marginTop: 2,
            }}
          >
            Honey
          </Text>
        </View>
      )}
    </View>
  );
}

export default Logo;
